    'di_q3': { type: 'mcq', questionText: { ar: 'في الأنظمة المحوسبة، البيانات الخام (Raw Data) هي:', en: 'In computerized systems, Raw Data is:' }, options: { ar: ['المطبوعات الورقية فقط', 'الملفات الإلكترونية الأصلية', 'كلام الموظفين', 'شاشة الحاسوب فقط'], en: ['Paper printouts only', 'Original electronic files', 'Staff verbal talk', 'Computer screen only'] }, correctAnswer: 1 },
