    'gdp_q5': { type: 'tf', difficulty: 'easy', questionText: { ar: 'هل يجب توثيق درجة الحرارة أثناء نقل الأدوية؟', en: 'Should temperature be documented during drug transport?' }, correctAnswer: true, explanation: { ar: 'توثيق درجة الحرارة مطلوب لضمان الامتثال لمعايير GDP', en: 'Temperature documentation is required to ensure GDP compliance' } },
    // Additional GDP questions
