    'gdp_q7': { type: 'mcq', difficulty: 'medium', questionText: { ar: 'أي مما يلي يُعد من علامات الأدوية المزورة؟', en: 'Which of the following is a sign of counterfeit drugs?' }, options: { ar: ['تغليف سليم مع رقم دفعة', 'تاريخ صلاحية واضح', 'تغليف غير عادي أو به أخطاء إملائية', 'ختم الشركة الرسمي'], en: ['Proper packaging with batch number', 'Clear expiry date', 'Unusual packaging or spelling errors', 'Official company seal'] }, correctAnswer: 2, explanation: { ar: 'التغليف غير العادي أو أخطاء الطباعة من علامات التزوير', en: 'Unusual packaging or printing errors are signs of counterfeiting' } },
    'gdp_q8': { type: 'mcq', difficulty: 'medium', questionText: { ar: 'ما هو الحد الأقصى للرطوبة النسبية في مستودع الأدوية؟', en: 'What is the maximum relative humidity in a drug warehouse?' }, options: { ar: ['30%', '45-65%', '80%', '90%'], en: ['30%', '45-65%', '80%', '90%'] }, correctAnswer: 1, explanation: { ar: 'الرطوبة النسبية يجب أن تكون بين 45-65%', en: 'Relative humidity should be between 45-65%' } },
    'gdp_q9': { type: 'tf', difficulty: 'medium', questionText: { ar: 'هل يمكن تخزين الأدوية الغذائية مع الأدوية في نفس المستودع؟', en: 'Can food items be stored with drugs in the same warehouse?' }, correctAnswer: false, explanation: { ar: 'يجب الفصل بين药品 والأغذية لتجنب التلوث المتبادل', en: 'Drugs and food must be separated to avoid cross-contamination' } },
    'gdp_q10': { type: 'mcq', difficulty: 'hard', questionText: { ar: 'ما هو الغرض من نظام التتبع (Traceability) في GDP؟', en: 'What is the purpose of Traceability in GDP?' }, options: { ar: ['زيادة الأرباح', 'تتبع المنتج من المصنّع للمريض', 'تقليل عدد الموظفين', 'تسريع عملية الشحن'], en: ['Increase profits', 'Track product from manufacturer to patient', 'Reduce staff', 'Speed up shipping'] }, correctAnswer: 1, explanation: { ar: 'التتبع يسمح بتحديد مصدر أي مشكلة والأدوية المزورة', en: 'Traceability allows identifying source of any problems and counterfeit drugs' } },
    'gdp_q11': { type: 'mcq', difficulty: 'hard', questionText: { ar: 'ما هي الطريقة الصحيحة للتعامل مع شحنة أدوية يصل معدل حرارتها خارج النطاق؟', en: 'What is the correct way to handle a drug shipment arriving with temperature out of range?' }, options: { ar: ['قبول الشحنة مباشرة', 'رفض الشحنة والإبلاغ عن المورد', 'تركها في الخارج', 'إضافتها لل مخزون'], en: ['Accept the shipment immediately', 'Reject the shipment and report the supplier', 'Leave it outside', 'Add it to stock'] }, correctAnswer: 1, explanation: { ar: 'الشحنات خارج نطاق الحرارة يجب رفضها والإبلاغ', en: 'Shipments out of temperature range must be rejected and reported' } },
    'gdp_q12': { type: 'fill', difficulty: 'medium', questionText: { ar: 'ما هو الاختصار لـ "ممارسات التوزيع الجيد"؟ (اكتب بالإنجليزية)', en: 'What is the abbreviation for "Good Distribution Practice"? (Write in English)' }, correctAnswers: ['GDP', 'G.D.P.', 'good distribution practice'] },
